pub fn insert_metadata(
    &mut self,
    contract: &QualifiedContractIdentifier,
    key: &str,
    value: &str,
) -> Result<(), VmInternalError> {
    let current = self.stack.last_mut().ok_or_else(|| {
        VmInternalError::Expect("ERROR: Clarity VM attempted PUT on non-nested context.".into())
    })?;

    let metadata_key = (contract.clone(), key.to_string());

    inner_put_data(
        &mut self.metadata_lookup_map,
        &mut current.metadata_edits,
        metadata_key,
        value.to_string(),
    );
    Ok(())
}

// Throws a NoSuchContract error if contract doesn't exist,
//   returns None if there is no such metadata field.
#[cfg_attr(feature = "profiler", stacks_profiler::profile)]
pub fn get_metadata(
    &mut self,
    contract: &QualifiedContractIdentifier,
    key: &str,
) -> Result<Option<String>, VmExecutionError> {
    self.stack.last().ok_or_else(|| {
        VmInternalError::Expect("ERROR: Clarity VM attempted GET on non-nested context.".into())
    })?;

    // This is THEORETICALLY a spurious clone, but it's hard to turn something like
    //  (&A, &B) into &(A, B).
    let metadata_key = (contract.clone(), key.to_string());
    let lookup_result = if self.query_pending_data {

        let cur_height: u64 = self.get_current_block_height().into();

        // reward for the *child* of this block must have matured, since that determines the
        // streamed tx fee reward portion
        if ((block_height + 1) as u64) + MINER_REWARD_MATURITY >= cur_height {
            return Ok(None);
        }

        let id_bhh = self.get_index_block_header_hash(block_height)?;
        let epoch = self.get_stacks_epoch_for_block(&id_bhh)?;
        let reward: u128 = self
            .headers_db
            .get_tokens_earned_for_block(&id_bhh, &epoch)
            .ok_or_else(|| {
                VmInternalError::Expect("FATAL: matured block has no recorded reward".into())
            })?;

        Ok(Some(reward))
    }

