import csv, glob, os
for fn in sorted(glob.glob('traces/tx-*-trace.csv')):
    rows=list(csv.DictReader(open(fn)))
    if not rows:
        print(fn, 'EMPTY')
        continue
    total=float(rows[0]['wall_ms'])
    sums={}
    calls={}
    # inclusive spans of direct interest (note repeated contexts count nested; this is descriptive, not exclusive total)
    for r in rows:
        key=(r['context'], r['span'], r['location'])
        sums[key]=sums.get(key,0)+float(r['wall_ms'])
        calls[key]=calls.get(key,0)+int(r['call_count'])
    print('\\n',fn,'tx_ms',total,'rows',len(rows))
    for context,span,loc in sorted(sums, key=lambda k:sums[k], reverse=True)[:25]:
        if span in ('at-block','evaluate_at_block','get_data','get_value','get','get_by_key','get_path','walk','walk_backptr','map-get?','contract-call?','ft-get-balance','fetch_entry_with_size','set_block_hash','get_block_at_height') or context.startswith('clarity::user'):
            print(f\"{span:24} {context[:58]:58} calls={calls[(context,span,loc)]:5d} sum_ms={sums[(context,span,loc)]:9.3f} loc={loc}\")
